const customEase: [number,number,number,number] = [0.16, 1, 0.3, 1];

/* ═══ BLUR TEXT ═══ */
function BlurText({ text, className = "", delay = 0 }: { text: string; className?: string; delay?: number }) {
  const words = text.split(" ");
  return (
    <motion.div className={className} initial="hidden" whileInView="visible" viewport={{ once: true, margin: "-50px" }} transition={{ staggerChildren: 0.03, delayChildren: delay }}>
      {words.map((word, i) => (
        <motion.span key={i} style={{ display: "inline-block", marginRight: "0.25em" }} variants={{ hidden: { filter: "blur(12px)", opacity: 0, y: 40 }, visible: { filter: "blur(0px)", opacity: 1, y: 0 } }} transition={{ duration: 0.6, ease: customEase }}>{word}</motion.span>
      ))}
    </motion.div>
  );
}

function Reveal({ children, delay = 0, className = "" }: { children: React.ReactNode; delay?: number; className?: string }) {
  return (<motion.div initial={{ opacity: 0, y: 40, filter: "blur(6px)" }} whileInView={{ opacity: 1, y: 0, filter: "blur(0px)" }} viewport={{ once: true, margin: "-50px" }} transition={{ duration: 0.8, delay, ease: customEase }} className={className}>{children}</motion.div>);
}

