  useEffect(()=>{if(phase!=="app"||!mapVisible||!mapRef.current||leafletMap.current)return;const init=async()=>{if(!document.getElementById("leaflet-css")){const l=document.createElement("link");l.id="leaflet-css";l.rel="stylesheet";l.href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css";document.head.appendChild(l);}if(!(window as any).L){await new Promise<void>(r=>{const s=document.createElement("script");s.src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js";s.onload=()=>r();document.head.appendChild(s);});}const L=(window as any).L;if(!mapRef.current||leafletMap.current)return;const map=L.map(mapRef.current,{center:[33.4484,-112.0740],zoom:10,zoomControl:true,attributionControl:false});L.tileLayer("https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",{maxZoom:19}).addTo(map);markersLayer.current=L.layerGroup().addTo(map);leafletMap.current=map;if(mapResults.length>0)updateMapMarkers(map,L,mapResults);};init();},[phase,mapVisible]);
  useEffect(()=>{if(!leafletMap.current||!(window as any).L)return;updateMapMarkers(leafletMap.current,(window as any).L,mapResults);},[mapResults]);

  function updateMapMarkers(map:any,L:any,results:any[]){if(!markersLayer.current)return;markersLayer.current.clearLayers();const pts:any[]=[];results.forEach(item=>{const zip=String(item.zip_code||"").trim();const coords=getZipCoords(zip);if(!coords)return;const r=riskOf(item.priority_score);const icon=L.divIcon({className:"",html:`<div style="position:relative;width:32px;height:32px;"><div style="position:absolute;inset:0;border-radius:50%;background:${r.c}22;border:1.5px solid ${r.c};animation:ping 1.5s ease-out infinite;"></div><div style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:10px;height:10px;border-radius:50%;background:${r.c};box-shadow:0 0 10px ${r.c};"></div></div>`,iconSize:[32,32],iconAnchor:[16,16]});const marker=L.marker(coords,{icon});marker.bindPopup(`<div style="background:rgba(10,5,0,.85);border:1px solid ${r.c}55;border-radius:16px;padding:14px 16px;font-family:'Barlow',sans-serif;color:#fff;min-width:190px;backdrop-filter:blur(16px);"><div style="font-size:9px;letter-spacing:3px;color:${r.c};margin-bottom:8px;text-transform:uppercase;font-weight:600;">● ${r.l}</div><div style="font-weight:600;font-size:14px;margin-bottom:3px;font-family:'Instrument Serif',serif;font-style:italic;color:#fbbf24;">${item.store_name||`ZIP ${zip}`}</div><div style="font-size:11px;color:rgba(255,255,255,.45);margin-bottom:12px;">ZIP ${zip}</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><div style="font-size:9px;color:rgba(255,255,255,.3);letter-spacing:2px;text-transform:uppercase;">Crimes</div><div style="color:#fff;font-weight:600;font-size:16px;">${(item.total_crimes??0).toLocaleString()}</div></div><div><div style="font-size:9px;color:rgba(255,255,255,.3);letter-spacing:2px;text-transform:uppercase;">Risk</div><div style="color:${r.c};font-weight:600;font-size:16px;">${item.priority_score??"N/A"}</div></div></div></div>`,{className:"aura-popup"});markersLayer.current.addLayer(marker);pts.push(coords);});if(pts.length>0){try{map.fitBounds(L.latLngBounds(pts),{padding:[40,40],maxZoom:13});}catch(e){}}}

  function handleAccept(){setDisclaimerExit(true);setTimeout(()=>{setPhase("exit");setTimeout(()=>setPhase("app"),900);},650);}
  const riskOf=(s:number)=>s>=50?{c:"#f87171",bg:"rgba(248,113,113,.05)",l:"CRITICAL"}:s>=20?{c:"#fbbf24",bg:"rgba(251,191,36,.05)",l:"ELEVATED"}:{c:"#34d399",bg:"rgba(52,211,153,.05)",l:"NOMINAL"};

  async function fire(){if(!question.trim()||loading)return;const q=question.trim();if(!hasToasted.current){hasToasted.current=true;setToastPhase("crack");setTimeout(()=>setToastPhase("open"),600);setTimeout(()=>setToastPhase("closing"),9500);setTimeout(()=>setToastPhase("hidden"),11200);}setQueryCount(c=>c+1);setMessages(p=>[...p,{role:"user",content:q}]);setLoading(true);setQuestion("");try{const res=await fetch("/api/query",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({question:q})});const data=await res.json();setMessages(p=>[...p,{role:"assistant",results:data.results,answer:data.answer}]);if(data.results?.length>0){const avg=data.results.reduce((a:number,r:any)=>a+(r.priority_score||0),0)/data.results.length;setAmbientRisk(avg>=50?"critical":avg>=20?"elevated":"nominal");const wc=data.results.filter((r:any)=>getZipCoords(String(r.zip_code||"").trim()));if(wc.length>0){setMapResults(data.results);setMapVisible(true);setTimeout(()=>document.getElementById("aura-map")?.scrollIntoView({behavior:"smooth",block:"center"}),700);}}}catch(e){console.error(e);}finally{setLoading(false);}}

