        {/* NAV */}
        <motion.nav initial={{opacity:0,y:-20}} animate={{opacity:1,y:0}} transition={{duration:.8,ease:customEase}} style={{position:"fixed",top:mobile?0:28,left:0,right:0,zIndex:100,padding:mobile?"0 16px":"12px 24px"}}><div style={{maxWidth:1600,margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"space-between"}}><button className="liquid-glass" style={{borderRadius:"50%",padding:12,border:"none",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}><Orbit size={22} color="#fbbf24"/></button>{!mobile&&(<div className="liquid-glass" style={{borderRadius:100,padding:"10px 8px 10px 28px",display:"flex",alignItems:"center",gap:28}}>{[["How It Works","#guide"],["Terminal","#terminal"],["System","#system"],["About","#about"]].map(([l,h])=>(<a key={l} href={h} style={{fontSize:13,color:"rgba(255,255,255,.6)",letterSpacing:".04em",fontWeight:500,transition:"color .2s"}} onMouseEnter={e=>(e.currentTarget.style.color="#fbbf24")} onMouseLeave={e=>(e.currentTarget.style.color="rgba(255,255,255,.6)")}>{l}</a>))}<a href="#terminal"><button style={{background:"#fbbf24",color:"#02040A",padding:"8px 20px",borderRadius:100,fontSize:13,fontWeight:700,border:"none",cursor:"pointer",display:"flex",alignItems:"center",gap:4}}>Get Started <ArrowUpRight size={14}/></button></a></div>)}<div style={{display:"flex",alignItems:"center",gap:10}}>{queryCount>0&&<div style={{fontSize:10,color:"#fbbf24",padding:"4px 12px",borderRadius:100,background:"rgba(251,191,36,.1)",border:"1px solid rgba(251,191,36,.2)",letterSpacing:".15em",fontWeight:600}}>{queryCount}Q</div>}{mobile&&(<button onClick={()=>setMenuOpen(o=>!o)} className="liquid-glass" style={{width:40,height:40,borderRadius:12,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:5,cursor:"pointer",padding:0,border:"none"}}><span style={{display:"block",width:18,height:1.5,background:"#fbbf24",borderRadius:1,transform:menuOpen?"rotate(45deg) translate(3px,3px)":"none",transition:"all .25s"}}/><span style={{display:"block",width:18,height:1.5,background:"#fbbf24",borderRadius:1,opacity:menuOpen?0:1,transition:"all .25s"}}/><span style={{display:"block",width:18,height:1.5,background:"#fbbf24",borderRadius:1,transform:menuOpen?"rotate(-45deg) translate(3px,-3px)":"none",transition:"all .25s"}}/></button>)}</div></div></motion.nav>

